################## ################## import Constants.s ################## ##################
    ### syscall constants
    PRINT_STRING            = 4
    PRINT_CHAR              = 11
    PRINT_INT               = 1

    ### MMIO addrs
    ANGLE                   = 0xffff0014
    ANGLE_CONTROL           = 0xffff0018
    VELOCITY                = 0xffff0010

    REQUEST_PUZZLE          = 0xffff00d0
    AVAIL_PUZZLES           = 0xffff00b4
    SUBMIT_SOLUTION         = 0xffff00d4
    CURRENT_PUZZLE          = 0xffff00b8

    BOT_X                   = 0xffff0020
    BOT_Y                   = 0xffff0024
    OTHER_X                 = 0xffff00a0
    OTHER_Y                 = 0xffff00a4

    NUM_CARROTS             = 0xffff0040
    NUM_BUNNIES_CARRIED     = 0xffff0050

    SEARCH_BUNNIES          = 0xffff0054
    CATCH_BUNNY             = 0xffff0058
    PUT_BUNNIES_IN_PLAYPEN  = 0xffff005c

    PLAYPEN_LOCATION        = 0xffff0044
    LOCK_PLAYPEN			= 0xffff0048
    UNLOCK_PLAYPEN			= 0xffff004c
    PLAYPEN_OTHER_LOCATION	= 0xffff00dc

    SCORES_REQUEST          = 0xffff1018

    TIMER                   = 0xffff001c

    BONK_INT_MASK           = 0x1000      ## Bonk
    BONK_ACK                = 0xffff0060  ## Bonk
    TIMER_INT_MASK          = 0x8000      ## Timer
    TIMER_ACK               = 0xffff006c  ## Timer
    REQUEST_PUZZLE_INT_MASK = 0x800       ## Puzzle
    REQUEST_PUZZLE_ACK		= 0xffff00e4  ## Puzzle
    BUNNY_MOVE_INT_MASK     = 0x400       ## Bunny Move
    BUNNY_MOVE_ACK          = 0xffff00e8  ## Bunny Move
    EX_CARRY_LIMIT_INT_MASK = 0x4000      ## Exceeding Carry Limit
    EX_CARRY_LIMIT_ACK      = 0xffff002c  ## Exceeding Carry Limit
    PLAYPEN_UNLOCK_INT_MASK = 0x2000      ## Playpen Unlock
    PLAYPEN_UNLOCK_ACK      = 0xffff0028  ## Playpen Unlock

    MMIO_STATUS             = 0xffff204c

################## ################## import Main.s ################## ##################
    .text
    main:
            #################### Enable Interrupts ####################
            li      $t4, 1
            or      $t4, $t4, TIMER_INT_MASK
            or      $t4, $t4, BONK_INT_MASK                         # enable bonk interrupt
            or      $t4, $t4, REQUEST_PUZZLE_INT_MASK               # enable puzzle interrupt
            or      $t4, $t4, PLAYPEN_UNLOCK_INT_MASK               # enable playpen unlock interrupt
            or      $t4, $t4, 1                                     # global enable
            mtc0    $t4, $12

            #################### Preprocessing ####################
            # Save the playpen location to memory
            lw      $t0, PLAYPEN_LOCATION                           # $t0 = &PLAYPEN_LOCATION
            and     $t1, $t0, 0xFFFF0000                            # $t1 = $t0 & 0xFFFF0000
            srl     $t1, $t1, 16                                    # <$t6> int _playpen_x = $t1 >> 16;
            and     $t2, $t0, 0x0000FFFF                            # <$t2> int _playpen_y = $t0 & 0x0000FFFF;
            la      $t3, playpen_x                                  # $t3 = &playpen_x
            sw      $t1, 0($t3)                                     # playpen_x = _playpen_x;
            la      $t4, playpen_y                                  # $t4 = &playpen_y
            sw      $t2, 0($t4)                                     # playpen_y = _playpen_y;

            # Save the enemy playpen location to memory
            lw      $t0, PLAYPEN_OTHER_LOCATION                     # $t0 = &PLAYPEN_OTHER_LOCATION
            and     $t5, $t0, 0xFFFF0000                            # $t5 = $t0 & 0xFFFF0000
            srl     $t5, $t5, 16                                    # <$t5> int _other_playpen_x = $t1 >> 16;
            and     $t6, $t0, 0x0000FFFF                            # <$t6> int _other_playpen_y = $t0 & 0x0000FFFF;
            la      $t3, other_playpen_x                            # $t3 = &other_playpen_x
            sw      $t5, 0($t3)                                     # other_playpen_x = _other_playpen_x;
            la      $t4, other_playpen_y                            # $t4 = &other_playpen_y
            sw      $t6, 0($t4)                                     # other_playpen_y = _other_playpen_y;

            # Calculate time_between_playpens
            sub     $t5, $t5, $t1                                   # <$t5> int deltaX = _other_playpen_x - _playpen_x;
            sub     $t6, $t6, $t2                                   # <$t6> int deltaY = _other_playpen_Y - _playpen_Y;
            mul     $t5, $t5, $t5                                   # <$t5> int deltaX_2 = deltaX * deltaX;
            mul     $t6, $t6, $t6                                   # <$t6> int deltaY_2 = deltaY * deltaY;
            add     $t5, $t6, $t5                                   # <$t5> int squared_sum = deltaX_2 + deltaY_2;
            mtc1    $t5, $f2                                        # $f2 <-- squared_sum
            cvt.s.w $f2, $f2                                        # $f2 = static_cast<float>(squared_sum)
            sqrt.s  $f2, $f2                                        # $f2 = sqrt(squared_sum)
            li      $t6, 1000                                       # $t6 = 1000
            mtc1    $t6, $f3                                        # $f3 <-- 1000
            cvt.s.w $f3, $f3                                        # $f3 = static_cast<float>(1000)
            mul.s   $f2, $f2, $f3                                   # float _ftime_between_playpens = 1000.0 * sqrt((_other_playpen_x - _playpen_x)**2 + (_other_playpen_Y - _playpen_Y)**2)
            cvt.w.s $f2, $f2                                        # $f2 = static_cast<int>(_ftime_between_playpens)
            mfc1    $t5, $f2                                        # <$t5> int _time_between_playpens = static_cast<int>(_ftime_between_playpens);
            la      $t0, time_between_playpens                      # $t0 = &time_between_playpens
            sw      $t5, 0($t0)                                     # time_between_playpens = _time_between_playpens;

            #################### Start Schmoovin' ####################
            jal     FSMTransitionFunction                           # Lets get ts on the road!

    #################### Tell 'em to bring out the whole ocean! ####################
    loop:
        jal  requestPuzzle
        move $a0, $v0
        jal  solvePuzzle                                        # Infinitely Solve Puzzles: Bands on Bands on Bands.
        j       loop                                            # MORE!!!!

################## ################## import FSMTransitionFunction.s ################## ##################
    # @function
    #
    # Transition Function for the FSM. Changes the FSM state and also does the proper action tied with the state.
    #
    # @UsedTemporaries: $t0, $t1, $t2
    #
    # @Params: None
    #
    # @Returns: void
    FSMTransitionFunction:
        sub     $sp, $sp, 4                             # Allocate 4 bytes on the stack
        sw      $ra, 0($sp)                             # Save $ra to the stack

        la      $t0, fsm_state                          # $t0 = &fsm_state
        lb		$t1, 0($t0)                             # Load the FSM State

        # Branch for each FSM State
        beq     $t1, 0, FSM_0                           # if fsm_state == 0, go to FSM_0
        beq     $t1, 1, FSM_1                           # if fsm_state == 1, go to FSM_1
        beq     $t1, 2, FSM_2                           # if fsm_state == 2, go to FSM_2
        beq     $t1, 3, FSM_3                           # if fsm_state == 3, go to FSM_3

        FSM_0:
            jal     PickBestBunny                       # (Bunny* best_bunny, float best_bunny_dist) = PickBestBunny()

            lw      $a0, 0($v0)                         # $a0 = best_bunny->x
            lw      $a1, 4($v0)                         # $a1 = best_bunny->y
            cvt.w.s $f0, $f0                            # $f0 = static_cast<int>(best_bunny_dist)
            mfc1    $a2, $f0                            # $a2 <-- $f0
            mul     $a2, $a2, 1000                      # $a2 = static_cast<int>(best_bunny_dist)*1000
            jal     MoveWithTime                        # MoveWithTime(best_bunny->x, best_bunny->y, static_cast<int>(best_bunny_dist)*1000); | Asynchronous Move

            la      $t0, fsm_state                      # $t0 = &fsm_state
            li      $t1, 1                              # $t1 = 1
            sb      $t1, 0($t0)                         # fsm_state = 1;
            j       FSM_Return                          # return;
        FSM_1:
            sw      $0, CATCH_BUNNY
            lw      $t0, MMIO_STATUS

            beq     $t0, 0, FSM_1_Bunny_Picked          # if bunny was picked up, jump to FSM_1_Bunny_Picked
            la      $t0, fsm_state                      # $t0 = &fsm_state
            sb      $0, 0($t0)                          # fsm_state = 0;
            j       FSM_0                               # Pick a new bunny until you actually succesfully pick one up

            FSM_1_Bunny_Picked:
                la      $t0, playpen_x                  # $t0 = &playpen_x
                lw      $a0, 0($t0)                     # $a0 = playpen_x | Extract x coordinate
                lw      $a1, 4($t0)                     # $a0 = playpen_y | Extract shifted y coordinate
                jal     Move                            # Move(playpen_x, playpen_y); | Asynchronous Move
                
                la      $t0, fsm_state                  # $t0 = &fsm_state
                li      $t1, 2                          # $t1 = 2
                sb      $t1, 0($t0)                     # fsm_state = 2;
                j       FSM_Return                      # return;
        FSM_2:
            sw      $0, LOCK_PLAYPEN                    # Lock the playpen
            lw      $t0, NUM_BUNNIES_CARRIED            # $t0 = *NUM_BUNNIES_CARRIED
            sw      $t0, PUT_BUNNIES_IN_PLAYPEN         # Put all of the bunnies in our playpen

            # Since we can only unlock their playpen once every 100,000 cycles,
            #   we can save the timestamp of when we last unlocked their pen
            #   and only move to their playpen and state 3 iff the current timestamp is
            #   more than 100,000 cycles after the saved timestamp, then save the current timestamp to do the same later.

            la      $t0, timestamp_can_unlock_enemy     # $t0 = &timestamp_can_unlock_enemy
            lw      $t0, 0($t0)                         # $t0 = timestamp_can_unlock_enemy
            la      $t1, time_between_playpens          # $t1 = &time_between_playpens   
            lw      $t1, 0($t1)                         # $t1 = time_between_playpens
            lw      $t2, TIMER($0)                      # <$t2> int current_time = *timer

            add     $t2, $t2, $t1                       # $t2 = current_time + time_between_playpens | the timestamp when we would reach the enemy playpen
            bgt     $t2, $t0, FSM_2_Sabotage            # if current_time + time_between_playpens > timestamp_can_unlock_enemy, jump to FSM_2_Sabotage

            la      $t0, fsm_state                      # $t0 = &fsm_state
            sb      $0, 0($t0)                          # fsm_state = 0;
            j       FSM_0                               # Immediatly look for another bunny as we can't unlock their playpen anyway

            FSM_2_Sabotage:
                la      $t0, other_playpen_x            # $t0 = &other_playpen_x
                lw      $a0, 0($t0)                     # $a0 = other_playpen_x | Extract x coordinate
                lw      $a1, 4($t0)                     # $a1 = other_playpen_y | Extract shifted y coordinate
                jal     Move                            # Move(other_playpen_x, other_playpen_y); | Asynchronous Move
            
                la      $t0, fsm_state                  # $t0 = &fsm_state
                li      $t1, 3                          # $t1 = 3
                sb      $t1, 0($t0)                     # fsm_state = 3;
                j       FSM_Return                      # return;
        FSM_3:
            sw      $0, UNLOCK_PLAYPEN                  # Unlock Opponent's Playpen
            lw      $t1, TIMER($0)                      # $t1 = *timer
            lw      $t2, MMIO_STATUS                    # $t2 = *MMIO_STATUS

            beq     $t2, 1, FSM_3_Continue              # if the unlock failed, jump to FSM_3_Continue and don't update timestamp_can_unlock_enemy
            la      $t0, timestamp_can_unlock_enemy     # $t0 = &timestamp_can_unlock_enemy
            add     $t1, $t1, 100000                    # $t1 = *timer + 100000
            sw      $t1, 0($t0)                         # timestamp_can_unlock_enemy = *timer + 100000
            
            FSM_3_Continue:
                la      $t0, fsm_state                  # $t0 = &fsm_state
                sb      $0, 0($t0)                      # fsm_state = 0;
                j       FSM_0                           # Immediatly look for the next bunny

        FSM_Return:
            lw      $ra, 0($sp)                         # Load $ra from the stack
            add		$sp, $sp, 4                         # Deallocate 4 bytes
            jr      $ra                                 # return;
        
################## ################## import Move.s ################## ##################
    # @async 
    # @function
    #
    # Asynchronously moves the bot to a specified coordinate.
    #
    # @UsedTemporaries:
    # - Integers: $t0, $t1, $t2, $t3
    # - Floating: $f2, $f3
    # 
    # @Params:
    # - $a0 (int target_x): The x coordinate of the target, [0,300]
    # - $a1 (int target_y): The y coordinate of the target, [0,300]
    #
    # @Returns: void
    Move:
        # Load our bots coordinates
        lw      $t0, BOT_X                      # <$t0> int bot_x = *BOT_X;
        lw      $t1, BOT_Y                      # <$t1> int bot_y = *BOT_Y;

        # Compute the angle
        sub     $t0, $a0, $t0                   # <$t0?> int deltaX = target_x - bot_x;
        sub     $t1, $a1, $t1                   # <$t1?> int deltaY = target_y - bot_y;

        mul     $t2, $t0, 601                   # $t2 = deltaX*601
        add     $t2, $t2, $t1                   # $t2 = deltaX*601 + deltaY
        sll     $t2, $t2, 1                     # $t2 = (deltaX*601 + deltaY)*2
        la      $t3, atan2lookup                # $t3 = &atan2lookup
        add     $t2, $t3, $t2                   # $t2 = &atan2lookup + (deltaX*601 + deltaY)*2
        lh      $t2, 0($t2)                     # <$t2> int theta = atan2lookup[deltaX][deltaY];

        # Turn
        sw      $t2, ANGLE                      # bot->set_angle = theta;
        li      $t3, 1                          # $t3 = 1
        sw      $t3, ANGLE_CONTROL              # bot->angle_control = 1; | Set the absolute orientation

        # Compute time to get there
        mul     $t0, $t0, $t0                   # <$t0> int deltaX_2 = deltaX * deltaX;
        mul     $t1, $t1, $t1                   # <$t1> int deltaY_2 = deltaY * deltaY;

        add     $t0, $t0, $t1                   # <$t0> int squared_sum = deltaX_2 + deltaY_2;
        mtc1    $t0, $f2                        # $f2 <-- squared_sum
        cvt.s.w $f2, $f2                        # $f2 = static_cast<float>(squared_sum)
        sqrt.s  $f2, $f2                        # $f2 = sqrt(squared_sum)

        li      $t1, 1000                       # $t1 = 1000
        mtc1    $t1, $f3                        # $f3 <-- 1000
        cvt.s.w $f3, $f3                        # $f3 = static_cast<float>(1000)
        
        mul.s   $f2, $f3, $f2                   # <$f2> float ftime_to_target = 1000.0 * sqrt(squared_sum);
        cvt.w.s $f2, $f2                        # $f2! = static_cast<int>(ftime_to_target)
        mfc1    $t2, $f2                        # <$t2!> int time_to_target = static_cast<int>(ftime_to_target);

        # Premeptively load the velocity
        li      $t3, 10                         # <$t3!> int velocity = 10; | Premeptively load the velocity
        
        # Request Timer Interrupt
        li      $t0, 1                          # $t0 = 1
        la      $t1, has_timer                  # $t1 = &has_timer
        sb      $t0, 0($t1)                     # has_timer = 1;
        
        lw      $t0, TIMER                      # $t0 = *TIMER
        add     $t0, $t0, $t2                   # <$t0> int timestamp = *TIMER + time_to_target;
        sw      $t0, TIMER                      # Request a timer interrupt for the time in `<t0> timestamp`
        
        # Move the spimbot
        sw      $t3, VELOCITY                   # *VELOCITY = velocity; i.e. *VELOCITY = 10;

        # Return
        jr      $ra                             # return;
        
    # @async 
    # @function
    #
    # Asynchronously moves the bot to a specified coordinate, without recomputing the time to get there.
    #
    # @UsedTemporaries:
    # - Integers: $t0, $t1, $t2, $t3
    # - Floating: None
    #
    # @Preconditions: $a2 is actually correct
    #
    # @Params:
    # - $a0 (int target_x): The x coordinate of the target, [0,300]
    # - $a1 (int target_y): The y coordinate of the target, [0,300]
    # - $a2 (int time_to_target): The time in cycles it will take the spimbot to get to the target
    #
    # @Returns: void
    MoveWithTime:
        # Load our bots coordinates
        lw      $t0, BOT_X                      # <$t0> int bot_x = *BOT_X;
        lw      $t1, BOT_Y                      # <$t1> int bot_y = *BOT_Y;

        # Compute the angle
        sub     $t0, $a0, $t0                   # <$t0?> int deltaX = target_x - bot_x;
        sub     $t1, $a1, $t1                   # <$t1?> int deltaY = target_y - bot_y;

        mul     $t2, $t0, 601                   # $t2 = deltaX*601
        add     $t2, $t2, $t1                   # $t2 = deltaX*601 + deltaY
        sll     $t2, $t2, 1                     # $t2 = (deltaX*601 + deltaY)*2
        la      $t3, atan2lookup                # $t3 = &atan2lookup
        add     $t2, $t3, $t2                   # $t2 = &atan2lookup + (deltaX*601 + deltaY)*2
        lh      $t2, 0($t2)                     # <$t2> int theta = atan2lookup[deltaX][deltaY];

        # Turn
        sw      $t2, ANGLE                      # bot->set_angle = theta;
        li      $t3, 1                          # $t3 = 1
        sw      $t3, ANGLE_CONTROL              # bot->angle_control = 1; | Set the absolute orientation

        # Premeptively load the velocity
        li      $t3, 10                         # <$t3!> int velocity = 10; | Premeptively load the velocity
        
        # Request Timer Interrupt
        li      $t0, 1                          # $t0 = 1
        la      $t1, has_timer                  # $t1 = &has_timer
        sb      $t0, 0($t1)                     # has_timer = 1;

        lw      $t0, TIMER                      # $t0 = *TIMER
        add     $t0, $t0, $a2                   # <$t0> int timestamp = *TIMER + time_to_target;
        sw      $t0, TIMER                      # Request a timer interrupt for the time in `<t0> timestamp`
        
        # Move the spimbot
        sw      $t3, VELOCITY                   # *VELOCITY = velocity; i.e. *VELOCITY = 10;

        # Return
        jr      $ra                             # return;

################## ################## import PickBestBunny.s ################## ##################
    # @function
    #
    # Chooses the best bunny to pursue based on the largest weight/travel-time ratio.
    # Ignores bunnies that cannot be reached before they jump. If two bunnies have
    # the same ratio, chooses the heavier bunny. Also returns the distance/time from
    # the bot to the chosen bunny.
    #
    # @UsedTemporaries:
    # - Integers: $t0, $t1, $t2, $t3, $t4, $t5
    # - Floating: $f2, $f3, $f4, $f5
    #
    # @Params: None
    #
    # @Returns:
    #   $v0 (Bunny*): best_bunny | A pointer to the optimal bunny
    #   $f0 (float): best_bunny_dist | The number of distance in pixels from the spimbot's current location to the best bunny
    PickBestBunny:
        la      $t0, bunnies_info
        sw      $t0, SEARCH_BUNNIES($0)         # <$t0!> BunniesInfo* bunnies_info = *SEARCH_BUNNIES;
        lw      $t1, 0($t0)                     # <$t1!> int num_bunnies = bunnies_info->num_bunnies;

        add     $v0, $t0, 4                     # <$v0!> Bunny* best_bunny = &bunnies_info->info[0];
        mtc1    $zero, $f0                      # <$f0!> float best_bunny_dist = 0.0f;
        mtc1    $zero, $f2                      # <$f2!> float biggest_ratio = 0.0f;
        
        move    $t2, $0                         # <$t2!> int i = 0;
        PBB_For:
            mul     $t3, $t2, 16                # $t3 = i*16
            add     $t3, $t0, $t3               # $t3 = bunnies_info + i*16
            add     $t3, $t3, 4                 # <$t3!> Bunny* b = &bunnies_info->info[i];

            # <$f3!> float cycles_from_bot_to_bunny = sqrt((bot->x - b->x)**2 + (bot->y - b->y)**2);
            lw      $t4, 0($t3)                 # $t4 = b->x
            lw      $t5, BOT_X($0)              # $t5 = bot->x
            sub     $t4, $t5, $t4               # $t4 = bot->x - b->x
            mtc1    $t4, $f3                    # $f3 <-- bot->x - b->x
            cvt.s.w $f3, $f3                    # $f3 = static_cast<float>(bot->x - b->x)
            mul.s   $f3, $f3, $f3               # $f3 = static_cast<float>(bot->x - b->x)**2

            lw      $t4, 4($t3)                 # $t4 = b->y
            lw      $t5, BOT_Y($0)              # $t5 = bot->y
            sub     $t4, $t5, $t4               # $t4 = bot->y - b->y
            mtc1    $t4, $f4                    # $f4 <-- bot-y - b->y
            cvt.s.w $f4, $f4                    # $f4 = static_cast<float>(bot-y - b->y)
            mul.s   $f4, $f4, $f4               # $f4 = static_cast<float>(bot-y - b->y)**2

            add.s   $f3, $f4, $f3               # $f3 = static_cast<float>(bot->x - b->x)**2 + static_cast<float>(bot->y - b->y)**2
            sqrt.s  $f3, $f3                    # <$f3!> float cycles_from_bot_to_bunny = sqrt((bot->x - b->x)**2 + (bot->y - b->y)**2);

            lw      $t4, 12($t3)                # $t4 = b->remaining_cycles;
            mtc1    $t4, $f4                    # $f4 <-- $t4
            cvt.s.w $f4, $f4                    # $f4 = static_cast<float>(b->remaining_cycles)

            c.le.s  $f4, $f3                    # FPCond = b->remaining_cycles <= cycles_from_bot_to_bunny
            bc1t    PBB_For_Inc                 # if (b->remaining_cycles {$f4} <= cycles_from_bot_to_bunny {$f3}) continue;

            # <$f4> float cycles_from_bunny_to_playpen = sqrt((playpen_x - b->x)**2 + (playpen_y - b->y)**2);
            lw      $t4, 0($t3)                 # $t4 = b->x
            la      $t5, playpen_x              # $t5 = &playpen_x
            lw      $t5, 0($t5)                 # $t5 = playpen_x
            sub     $t4, $t5, $t4               # $t4 = playpen_x - b->x
            mtc1    $t4, $f4                    # $f4 <-- playpen_x - b->x
            cvt.s.w $f4, $f4                    # $f4 = static_cast<float>(playpen_x - b->x)
            mul.s   $f4, $f4, $f4               # $f4 = static_cast<float>(playpen_x - b->x)**2

            lw      $t4, 4($t3)                 # $t4 = b->y
            la      $t5, playpen_y              # $t5 = &playpen_y
            lw      $t5, 0($t5)                 # $t5 = playpen_y
            sub     $t4, $t5, $t4               # $t4 = playpen_y - b->y
            mtc1    $t4, $f5                    # $f5 <-- playpen_y - b->y
            cvt.s.w $f5, $f5                    # $f5 = static_cast<float>(playpen_y - b->y)
            mul.s   $f5, $f5, $f5               # $f5 = static_cast<float>(playpen_y - b->y)**2

            add.s   $f4, $f4, $f5               # $f3 = static_cast<float>(playpen_x - b->x)**2 + static_cast<float>(playpen_y - b->y)**2
            sqrt.s  $f4, $f4                    # # <$f4> float cycles_from_bunny_to_playpen = sqrt((playpen_x - b->x)**2 + (playpen_y - b->y)**2);

            add.s   $f4, $f3, $f4               # <$f4> float travel_time = cycles_from_bot_to_bunny + cycles_from_bunny_to_playpen;
            lw      $t4, 8($t3)                 # $t4! = b->weight
            mtc1    $t4, $f5                    # $f5 <-- $t4
            cvt.s.w $f5, $f5                    # $f5 = static_cast<float>(b->weight)
            div.s   $f5, $f5, $f4               # <$f5!> float ratio = static_cast<float>(b->weight) / travel_time;

            PBB_For_If:
                c.le.s  $f5, $f2                # FPCond = ratio <= biggest_ratio
                bc1t    PBB_For_Elif            # if ratio <= biggest_ratio, goto PBB_For_Elif

                mov.s   $f2, $f5                # biggest_ratio = ratio;
                move    $v0, $t3                # best_bunny = b;
                mov.s   $f0, $f3                # best_bunny_dist = cycles_from_bot_to_bunny;

                j       PBB_For_Inc
            PBB_For_Elif:
                c.eq.s  $f5, $f2                # FPCond = ratio == biggest_ratio
                bc1f    PBB_For_Inc             # if ratio != biggest_ratio, goto PBB_For_Inc
                lw      $t5, 8($v0)             # $t5 = best_bunny->weight
                ble     $t4, $t5, PBB_For_Inc   # if b->weight <= best_bunny->weight, goto PBB_For_Inc

                mov.s   $f2, $f5                # biggest_ratio = ratio;
                move    $v0, $t3                # best_bunny = b;
                mov.s   $f0, $f3                # best_bunny_dist = cycles_from_bot_to_bunny;


            PBB_For_Inc:
                add     $t2, $t2, 1             # ++i;
                blt		$t2, $t1, PBB_For       # if i < bunnies_info->num_bunnies then goto PBB_For

            jr      $ra                         # return { best_bunny, best_bunny_dist };
################## ################## import SolveGiven.s ################## ##################
    # @function
    #
    # Requests a puzzle
    #
    # Ovewrites: $t0, $t1, $t2
    # Returns:
    #   - $v0: The id of the requested puzzle
    requestPuzzle:
        la  $t0, puzzle_received
        sb  $0, 0($t0)                                  # puzzle_received = false;

        la  $t1, puzzle
        sw  $t1, REQUEST_PUZZLE($0)                     # Request a puzzle

        la  $t1, num_puzzles_requested
        lw  $v0, 0($t1)                                 # int puzzle_num = num_puzzles_requested;
        add $t2, $v0, 1                                 # num_puzzles_requested++;
        sw  $t2, 0($t1)                                 # store incremeneted num_puzzles_requested

        waitForPuzzle:
            lb  $t1, 0($t0)                             # $t0 = puzzle_received
            bne $t1, 0, receivedPuzzle                  # Break iff ~(puzzle_received == 0)
            j   waitForPuzzle                           # Wait for the puzzle
        receivedPuzzle:
            jr  $ra                                     # return puzzle_num;

    solvePuzzle:
        sub $sp, $sp, 8
        sw  $ra, 0($sp)
        sw  $a0, 4($sp)

        # Zero the board
        la  $t0, puzzle
        lw  $a0, 0($t0)
        lw  $a1, 4($t0)
        la  $a2, solution
        jal zero_board                          # zero_board(puzzle.num_rows, puzzle.num_cols, &solution);

        la  $a0, puzzle
        la  $a1, solution
        li  $a2, 0
        li  $a3, 0
        jal solve                              # bool got_sol = solve(&puzzle, &solution, 0, 0);

        lw  $t0, 4($sp)
        sw  $t0, CURRENT_PUZZLE($0)             # *CURRENT_PUZZLE = puzzle_num;

        la  $t0, solution
        sw  $t0, SUBMIT_SOLUTION($0)            # *SUBMIT_SOLUTION = &solution;

        lw  $t0, MMIO_STATUS($0)                # $t0 = *MMIO_STATUS;

        slt $t0, $0, $t0                        # $t0 = 1 if 0 != *MMIO_STATUS else $t0 = 0
        li  $t1, 1
        sub $t0, $t1, $t0                       # bool correct = *MMIO_STATUS == 0;

        and $v0, $v0, $t0                       # $v0 = got_sol && correct

        lw  $ra, 0($sp)
        add $sp, $sp, 8
        jr  $ra                                 # return got_sol && correct;

    #########################################
    zero_board:
        li      $t0, 0              # row = 0

    row_loop:
        bge     $t0, $a0, zero_done      # if row >= num_rows, exit
        li      $t1, 0              # col = 0

    col_loop:
        bge     $t1, $a1, next_row_zero  # if col >= num_cols, next row

        # Calculate index: row * num_cols + col
        mul     $t2, $t0, $a1       # t2 = row * num_cols
        add     $t2, $t2, $t1       # t2 = row * num_cols + col
        add     $t3, $a2, $t2       # t3 = &solution[row * num_cols + col]
        sb      $zero, 0($t3)       # solution[index] = 0

        addi    $t1, $t1, 1         # col++
        j       col_loop

    next_row_zero:
        addi    $t0, $t0, 1         # row++
        j       row_loop

    zero_done:
        jr      $ra
    #########################################
    board_done_given:
        li      $t0, 0

    row_loop_board_done_given:
        bge     $t0, $a0, all_zero_given
        li      $t1, 0

    col_loop_board_done_given:
        bge     $t1, $a1, next_row_given

        mul     $t2, $t0, $a1
        add     $t2, $t2, $t1
        add     $t3, $a2, $t2

        lbu     $t4, 0($t3)
        bne     $t4, $0, found_nonzero_given

        addi    $t1, $t1, 1
        j       col_loop_board_done_given

    next_row_given:
        addi    $t0, $t0, 1
        j       row_loop_board_done_given

    found_nonzero_given:
        li      $v0, 0
        jr      $ra

    all_zero_given:
        li      $v0, 1
        jr      $ra

    #########################################

    toggle_light:
        # t0=num_rows, t1=num_cols, t2=num_colors
        lw      $t0, 0($a2)
        lw      $t1, 4($a2)
        lw      $t2, 8($a2)

        # t3 = &board[0]
        addi    $t3, $a2, 12

    # addr = board_base + (row*num_cols + col)
    # val = (lbu(addr) + action_num) % num_colors
    # sb(val, addr)

        ######## center: (row, col)
        mul     $t4, $a0, $t1
        add     $t4, $t4, $a1
        add     $t5, $t3, $t4

        lbu     $t6, 0($t5)
        add     $t6, $t6, $a3
        rem     $t6, $t6, $t2
        sb      $t6, 0($t5)

        ######## if (row > 0) : up (row-1, col)
        slt     $t8, $zero, $a0          # t8 = (0 < row)
        beq     $t8, $zero, SKIP_UP

        addi    $t9, $a0, -1
        mul     $t4, $t9, $t1
        add     $t4, $t4, $a1
        add     $t5, $t3, $t4

        lbu     $t6, 0($t5)
        add     $t6, $t6, $a3
        rem     $t6, $t6, $t2
        sb      $t6, 0($t5)

    SKIP_UP:
        ######## if (col > 0) : left (row, col-1)
        slt     $t8, $zero, $a1          # t8 = (0 < col)
        beq     $t8, $zero, SKIP_LEFT

        addi    $t9, $a1, -1
        mul     $t4, $a0, $t1
        add     $t4, $t4, $t9
        add     $t5, $t3, $t4

        lbu     $t6, 0($t5)
        add     $t6, $t6, $a3
        rem     $t6, $t6, $t2
        sb      $t6, 0($t5)
    SKIP_LEFT:
        ######## if (row < num_rows - 1) : down (row+1, col)
        addi    $t9, $t0, -1             # t9 = num_rows - 1
        slt     $t8, $a0, $t9            # t8 = (row < num_rows-1)
        beq     $t8, $zero, SKIP_DOWN

        addi    $t9, $a0, 1
        mul     $t4, $t9, $t1
        add     $t4, $t4, $a1
        add     $t5, $t3, $t4

        lbu     $t6, 0($t5)
        add     $t6, $t6, $a3
        rem     $t6, $t6, $t2
        sb      $t6, 0($t5)
    SKIP_DOWN:
        ######## if (col < num_cols - 1) : right (row, col+1)
        addi    $t9, $t1, -1             # t9 = num_cols - 1
        slt     $t8, $a1, $t9            # t8 = (col < num_cols-1)
        beq     $t8, $zero, DONE

        addi    $t9, $a1, 1
        mul     $t4, $a0, $t1
        add     $t4, $t4, $t9
        add     $t5, $t3, $t4

        lbu     $t6, 0($t5)
        add     $t6, $t6, $a3
        rem     $t6, $t6, $t2
        sb      $t6, 0($t5)

    DONE:
        jr      $ra

    #########################################

    linearize:
        bne $a0 $0 not_base
        li $v0 0
        jr $ra

    not_base:
        sub $sp $sp 4
        sw $ra 0($sp)
        li $t0 0

    for:
        bge $t0 4 after_for
        mul $t3 $t0 4 # 4*i
        add $t3 $t3 4 # 4*i +4
        add $t2 $a0 $t3 #&node->data[i]
        lw $t4 0($t2)  # node->data[i]
        sw $t4 0($a1)  # *array = node->data[i];
        addi $a1 $a1 4 # array ++
        addi $t0 $t0 1 # i++

        j for

    after_for:
        lw $a0 0($a0)
        jal linearize
        lw $ra 0($sp)
        add $sp $sp 4
        jr $ra

    #########################################

    solve:
    # solve(LightsOuts* puzzle, unsigned char* solution, int row, int col)
    # $a0 = puzzle, $a1 = solution, $a2 = row, $a3 = col
    # Returns: $v0 = bool (0 or 1)

        # Save callee-saved registers
        sub     $sp, $sp, 36
        sw      $ra, 0($sp)
        sw      $s0, 4($sp)
        sw      $s1, 8($sp)
        sw      $s2, 12($sp)
        sw      $s3, 16($sp)
        sw      $s4, 20($sp)
        sw      $s5, 24($sp)
        sw      $s6, 28($sp)
        sw      $s7, 32($sp)

        # Save arguments to $s registers
        move    $s0, $a0        # $s0 = puzzle
        move    $s1, $a1        # $s1 = solution
        move    $s2, $a2        # $s2 = row
        move    $s3, $a3        # $s3 = col

        # Load struct fields
        lw      $s4, 0($s0)     # $s4 = num_rows = puzzle->num_rows
        lw      $s5, 4($s0)     # $s5 = num_cols = puzzle->num_cols
        lw      $s6, 8($s0)     # $s6 = num_colors = puzzle->num_colors

        # Calculate next_row = ((col == num_cols-1) ? row + 1 : row)
        sub     $t0, $s5, 1     # $t0 = num_cols - 1
        bne     $s3, $t0, solve_same_row
        add     $s7, $s2, 1     # next_row = row + 1
        j       solve_check_bounds
    solve_same_row:
        move    $s7, $s2        # next_row = row

    solve_check_bounds:
        # if (row >= num_rows || col >= num_cols)
        bge     $s2, $s4, solve_call_board_done
        bge     $s3, $s5, solve_call_board_done
        j       solve_check_row

    solve_call_board_done:
        # return board_done(num_rows, num_cols, puzzle->board)
        move    $a0, $s4        # num_rows
        move    $a1, $s5        # num_cols
        add     $a2, $s0, 12    # puzzle->board (offset 12)
        jal     board_done_given
        j       solve_return

    solve_check_row:
        # if (row != 0)
        beq     $s2, $0, solve_first_row

        # Row != 0 case
        # int actions = (num_colors - puzzle->board[(row-1)*num_cols + col]) % num_colors
        sub     $t0, $s2, 1     # row - 1
        mul     $t0, $t0, $s5   # (row-1) * num_cols
        add     $t0, $t0, $s3   # (row-1)*num_cols + col
        add     $t1, $s0, 12    # puzzle->board
        add     $t1, $t1, $t0   # &puzzle->board[(row-1)*num_cols + col]
        lbu     $t2, 0($t1)     # puzzle->board[(row-1)*num_cols + col]
        sub     $t3, $s6, $t2   # num_colors - board[...]
        rem     $t3, $t3, $s6   # actions = ... % num_colors

        # Store actions in stack for later use
        sub     $sp, $sp, 4
        sw      $t3, 0($sp)     # save actions

        # solution[row*num_cols + col] = actions
        mul     $t0, $s2, $s5   # row * num_cols
        add     $t0, $t0, $s3   # row*num_cols + col
        add     $t1, $s1, $t0   # &solution[row*num_cols + col]
        sb      $t3, 0($t1)

        # toggle_light(row, col, puzzle, actions)
        move    $a0, $s2
        move    $a1, $s3
        move    $a2, $s0
        move    $a3, $t3
        jal     toggle_light

        # Prepare recursive call: solve(puzzle, solution, next_row, (col+1) % num_cols)
        add     $t0, $s3, 1     # col + 1
        rem     $t0, $t0, $s5   # (col + 1) % num_cols
        move    $a0, $s0
        move    $a1, $s1
        move    $a2, $s7
        move    $a3, $t0
        jal     solve

        # if (solve(...)) return true
        bne     $v0, $0, solve_row_return_true

        # solution[row*num_cols + col] = 0
        mul     $t0, $s2, $s5
        add     $t0, $t0, $s3
        add     $t1, $s1, $t0
        sb      $0, 0($t1)

        # Restore actions from stack
        lw      $t3, 0($sp)

        # toggle_light(row, col, puzzle, num_colors - actions)
        sub     $t4, $s6, $t3   # num_colors - actions
        move    $a0, $s2
        move    $a1, $s3
        move    $a2, $s0
        move    $a3, $t4
        jal     toggle_light

        # Clean up stack and return false
        add     $sp, $sp, 4
        li      $v0, 0
        j       solve_return

    solve_row_return_true:
        add     $sp, $sp, 4     # clean up actions from stack
        li      $v0, 1
        j       solve_return

    solve_first_row:
        # for(char actions = 0; actions < num_colors; actions++)
        li      $t6, 0          # actions = 0

        # Save actions counter in stack
        sub     $sp, $sp, 4

    solve_loop:
        bge     $t6, $s6, solve_loop_end

        # Save actions to stack
        sw      $t6, 0($sp)

        # solution[row*num_cols + col] = actions
        mul     $t0, $s2, $s5   # row * num_cols
        add     $t0, $t0, $s3   # row*num_cols + col
        add     $t1, $s1, $t0   # &solution[row*num_cols + col]
        sb      $t6, 0($t1)

        # toggle_light(row, col, puzzle, actions)
        move    $a0, $s2
        move    $a1, $s3
        move    $a2, $s0
        move    $a3, $t6
        jal     toggle_light

        # Prepare recursive call: solve(puzzle, solution, next_row, (col+1) % num_cols)
        add     $t0, $s3, 1     # col + 1
        rem     $t0, $t0, $s5   # (col + 1) % num_cols
        move    $a0, $s0
        move    $a1, $s1
        move    $a2, $s7
        move    $a3, $t0
        jal     solve

        # if (solve(...)) return true
        bne     $v0, $0, solve_loop_return_true

        # Restore actions from stack
        lw      $t6, 0($sp)

        # toggle_light(row, col, puzzle, num_colors - actions)
        sub     $t4, $s6, $t6   # num_colors - actions
        move    $a0, $s2
        move    $a1, $s3
        move    $a2, $s0
        move    $a3, $t4
        jal     toggle_light

        # solution[row*num_cols + col] = 0
        mul     $t0, $s2, $s5
        add     $t0, $t0, $s3
        add     $t1, $s1, $t0
        sb      $0, 0($t1)

        # Restore actions and increment
        lw      $t6, 0($sp)
        add     $t6, $t6, 1
        j       solve_loop

    solve_loop_return_true:
        add     $sp, $sp, 4     # clean up actions from stack
        li      $v0, 1
        j       solve_return

    solve_loop_end:
        add     $sp, $sp, 4     # clean up actions from stack
        li      $v0, 0

    solve_return:
        # Restore callee-saved registers
        lw      $ra, 0($sp)
        lw      $s0, 4($sp)
        lw      $s1, 8($sp)
        lw      $s2, 12($sp)
        lw      $s3, 16($sp)
        lw      $s4, 20($sp)
        lw      $s5, 24($sp)
        lw      $s6, 28($sp)
        lw      $s7, 32($sp)
        add     $sp, $sp, 36
        jr      $ra

################## ################## import Kernel.s ################## ##################
    # ======================== kernel code ================================
    .kdata
    chunkIH:    .space 64
    kernel_stack: .space 64
    kernel_stack_top:               # stack grows down, so point to the end
    non_intrpt_str:    .asciiz "Non-interrupt exception\n"
    unhandled_str:    .asciiz "Unhandled interrupt type\n"
    .ktext 0x80000180
    interrupt_handler:
    .set noat
        move    $k1, $at                    # Save $at
                                            # NOTE: Don't touch $k1 or else you destroy $at!
    .set at
        la      $k0, chunkIH
        sw      $a0, 0($k0)                 # Get some free registers
        sw      $a1, 4($k0)                 # Get some free registers
        sw      $a2, 8($k0)                 # Get some free registers
        sw      $a3, 12($k0)                 # Get some free registers
        sw      $v0, 16($k0)                 # by storing them to a global variable
        sw      $v1, 20($k0)                 # by storing them to a global variable
        sw      $t0, 24($k0)
        sw      $t1, 28($k0)
        sw      $t2, 40($k0)
        sw      $t3, 44($k0)
        sw      $t4, 48($k0)
        sw      $t5, 52($k0)
        sw      $ra, 56($k0)
        sw      $sp, 60($k0)
        la      $sp, kernel_stack_top       # Temporarily Switch to Kernel stack

        # Save coprocessor1 registers!
        # If you don't do this and you decide to use division or multiplication
        #   in your main code, and interrupt handler code, you get WEIRD bugs.
        mfhi    $t0
        sw      $t0, 32($k0)
        mflo    $t0
        sw      $t0, 36($k0)

        mfc0    $k0, $13                    # Get Cause register
        srl     $a0, $k0, 2
        and     $a0, $a0, 0xf               # ExcCode field
        bne     $a0, 0, non_intrpt


    interrupt_dispatch:                     # Interrupt:
        mfc0    $k0, $13                    # Get Cause register, again
        beq     $k0, 0, done                # handled all outstanding interrupts

        and     $a0, $k0, BONK_INT_MASK     # is there a bonk interrupt?
        bne     $a0, 0, bonk_interrupt

        and     $a0, $k0, TIMER_INT_MASK    # is there a timer interrupt?
        bne     $a0, 0, timer_interrupt

        and     $a0 $k0 REQUEST_PUZZLE_INT_MASK
        bne     $a0 0 request_puzzle_interrupt

        and     $a0 $k0 PLAYPEN_UNLOCK_INT_MASK
        bne     $a0 0 playpen_unlock_interrupt

        li      $v0, PRINT_STRING           # Unhandled interrupt types
        la      $a0, unhandled_str
        syscall
        j       done

    bonk_interrupt:
        sw      $0, BONK_ACK                # Acknwoledge the bonk
        sw      $0, VELOCITY                # Set the velocity to 0

        la      $t0, has_timer              # $t0 = &has_timer
        sb      $0, 0($t0)                  # has_timer = false; | Ignore the next timer interrupt to prevent double FSM transitioning

        la      $t0, FSMTransitionFunction  # $t0 = &FSMTransitionFunction
        jalr    $t0                         # Call delta

        j       interrupt_dispatch          # see if other interrupts are waiting

    timer_interrupt:
        sw      $0, TIMER_ACK               # Acknowledge the timer interrupt
        sw      $0, VELOCITY                # Set the velocity to 0

        la      $t0, has_timer              # $t0 = &has_timer
        lb		$t1, 0($t0)                 # $t1 = has_timer
        beq     $t1, 0, interrupt_dispatch  # Shortcircuit if we are supposed to ignore this interrupt

        sb      $0, 0($t0)                  # has_timer = 0;

        la      $t0, FSMTransitionFunction  # $t0 = &FSMTransitionFunction
        jalr    $t0                         # Call delta

        j       interrupt_dispatch          # see if other interrupts are waiting

    request_puzzle_interrupt:
        sw      $0, REQUEST_PUZZLE_ACK      # Acknowledge the puzzle request interrupt

        li	    $t0, 1
        sb	    $t0, puzzle_received        # Set the puzzle_received flag to 1    
        
        j       interrupt_dispatch          # see if other interrupts are waiting

    playpen_unlock_interrupt:
        sw      $0, PLAYPEN_UNLOCK_ACK      # Acknowledge the puzzle request interrupt   
        
        j       interrupt_dispatch          # see if other interrupts are waiting

    non_intrpt:                             # was some non-interrupt
        li      $v0, PRINT_STRING
        la      $a0, non_intrpt_str
        syscall                             # print out an error message
        # fall through to done

    done:
        la      $k0, chunkIH

        # Restore coprocessor1 registers!
        # If you don't do this and you decide to use division or multiplication
        #   in your main code, and interrupt handler code, you get WEIRD bugs.
        lw      $t0, 32($k0)
        mthi    $t0
        lw      $t0, 36($k0)
        mtlo    $t0

        lw      $a0, 0($k0)                 # Restore saved registers
        lw      $a1, 4($k0)                 
        lw      $a2, 8($k0)
        lw      $a3, 12($k0)
        lw      $v0, 16($k0)
        lw      $v1, 20($k0)
        lw      $t0, 24($k0)
        lw      $t1, 28($k0)
        lw      $t2, 40($k0)
        lw      $t3, 44($k0)
        lw      $t4, 48($k0)
        lw      $t5, 52($k0)
        lw      $ra, 56($k0)
        lw      $sp, 60($k0)

    .set noat
        move    $at, $k1                    # Restore $at
    .set at
        eret

################## ################## import DataSegment.s ################## ##################
    .data
    .align 4
    bunnies_info: .space 484                                        # Space for the BunniesInfo Struct

